SELECT commitment_id, commitment_amount
FROM commitments
WHERE year = 2022;

SELECT status, COUNT(*) AS commitment_count
FROM commitments
GROUP BY status;

SELECT COUNT(commitment_id) AS num_approved_commitments
FROM commitments
WHERE status = 'approved';

SELECT MAX(change_date) AS latest_change_date
FROM commitment_history
WHERE commitment_id = 1;

SELECT commitment_id, MAX(change_date) AS latest_change_date
FROM commitment_history
GROUP BY commitment_id;
